import React from 'react';
import axios from 'axios';

function NoteList({ notes, fetchNotes }) {
  const deleteNote = async (id) => {
    try {
      await axios.delete(`http://localhost:5001/api/notes/${id}`);
      fetchNotes();
    } catch (err) { console.error(err); }
  };

  const gridStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '24px'
  };

  const cardStyle = {
    background: '#fff',
    padding: '24px',
    borderRadius: '16px',
    border: '1px solid #e2e8f0',
    display: 'flex',
    flexDirection: 'column',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.05)',
    transition: 'all 0.3s ease'
  };

  const deleteBtnStyle = {
    backgroundColor: '#fff1f2',
    color: '#e11d48',
    border: 'none',
    padding: '8px 12px',
    borderRadius: '8px',
    fontSize: '0.85rem',
    fontWeight: '600',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
    width: 'fit-content',
    marginTop: 'auto'
  };

  return (
    <div style={gridStyle}>
      {notes.length === 0 ? (
        <p style={{ gridColumn: '1/-1', textAlign: 'center', color: '#94a3b8' }}>No notes found yet.</p>
      ) : (
        notes.map((note) => (
          <div 
            key={note._id} 
            style={cardStyle}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-5px)';
              e.currentTarget.style.boxShadow = '0 20px 25px -5px rgba(0, 0, 0, 0.1)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 4px 6px -1px rgba(0, 0, 0, 0.05)';
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px' }}>
              <span style={{ fontSize: '10px', fontWeight: '800', color: '#4f46e5', textTransform: 'uppercase', background: '#eef2ff', padding: '2px 8px', borderRadius: '10px' }}>Documentation</span>
              <span style={{ fontSize: '0.75rem', color: '#94a3b8' }}>{new Date().toLocaleDateString()}</span>
            </div>

            <h3 style={{ fontSize: '1.2rem', margin: '0 0 10px 0', color: '#1e293b' }}>{note.title}</h3>
            <p style={{ fontSize: '0.95rem', color: '#64748b', lineHeight: '1.6', marginBottom: '20px' }}>{note.content}</p>

            <button 
              style={deleteBtnStyle} 
              onClick={() => deleteNote(note._id)}
              onMouseOver={(e) => e.target.style.backgroundColor = '#ffe4e6'}
              onMouseOut={(e) => e.target.style.backgroundColor = '#fff1f2'}
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default NoteList;
